import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface BloodPressureReading {
  systolic: number;
  diastolic: number;
  category: string;
  date: string;
}

interface DailyTrend {
  day: string;
  systolic: number;
  diastolic: number;
}

interface BloodPressureData {
  latestReading: BloodPressureReading;
  weeklyTrend: DailyTrend[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const data = response.data as BloodPressureData;
  const meta = response.meta as MetaData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Latest Reading
            </Typography>
            <Typography variant="h6" fontWeight={600} sx={{ color: meta.primaryColor }}>
              {data.latestReading.systolic}/{data.latestReading.diastolic} mmHg
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Category: {data.latestReading.category}
            </Typography>
            <Typography variant="caption" color="text.secondary">
              {new Date(data.latestReading.date).toLocaleDateString()}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: data.weeklyTrend.map(d => d.systolic),
                  color: meta.primaryColor,
                  label: 'Systolic',
                },
                {
                  type: 'line',
                  data: data.weeklyTrend.map(d => d.diastolic),
                  color: meta.accentColor,
                  label: 'Diastolic',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: data.weeklyTrend.map(d => d.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'pressure' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="pressure"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
